+import {IgnoreTypes} from '../utils/ignore-types';
+import {Options, RuleType} from '../rules';
+import RuleBuilder, {DropdownOptionBuilder, ExampleBuilder, OptionBuilderBase} from './rule-builder';
+
+type LinkStyleValue = 'no-change' | 'markdown' | 'wiki';
+
+class LinkStyleOptions implements Options {
+  linkStyle: LinkStyleValue = 'no-change';
+  imageStyle: LinkStyleValue = 'no-change';
+}
+
+type MarkdownLink = {
+  end: number,
+  label: string,
+  target: string,
+};
+
+@RuleBuilder.register
+export default class LinkStyle extends RuleBuilder<LinkStyleOptions> {
+  constructor() {
+    super({
+      nameKey: 'rules.link-style.name',
+      descriptionKey: 'rules.link-style.description',
+      type: RuleType.CONTENT,
+      ruleIgnoreTypes: [IgnoreTypes.yaml, IgnoreTypes.code, IgnoreTypes.inlineCode, IgnoreTypes.math, IgnoreTypes.inlineMath, IgnoreTypes.html, IgnoreTypes.templaterCommand, IgnoreTypes.obsidianMultiLineComments, IgnoreTypes.table],
+    });
+  }
+
+  get OptionsClass(): new () => LinkStyleOptions {
+    return LinkStyleOptions;
+  }
+
+  apply(text: string, options: LinkStyleOptions): string {
+    if (options.linkStyle === 'markdown') {
+      text = wikiToMarkdown(text, false);
+    } else if (options.linkStyle === 'wiki') {
+      text = markdownToWiki(text, false);
+    }
+
+    if (options.imageStyle === 'markdown') {
+      text = wikiToMarkdown(text, true);
+    } else if (options.imageStyle === 'wiki') {
+      text = markdownToWiki(text, true);
+    }
+
+    return text;
+  }
+
+  get exampleBuilders(): ExampleBuilder<LinkStyleOptions>[] {
+    return [
+      new ExampleBuilder({
+        description: 'Convert wiki links and embeds to Markdown',
+        before: '[[Page#Heading]] and ![[image.png|300x200]]',
+        after: '[Page > Heading](Page#Heading) and ![image.png](image.png)',
+        options: {linkStyle: 'markdown', imageStyle: 'markdown'},
+      }),
+      new ExampleBuilder({
+        description: 'Convert inline Markdown links and images to wiki syntax',
+        before: '[Page > Heading](Page#Heading) and ![alt](image.png)',
+        after: '[[Page#Heading]] and ![[image.png|alt]]',
+        options: {linkStyle: 'wiki', imageStyle: 'wiki'},
+      }),
+    ];
+  }
+
+  get optionBuilders(): OptionBuilderBase<LinkStyleOptions>[] {
+    return ['linkStyle', 'imageStyle'].map((optionsKey) => new DropdownOptionBuilder<LinkStyleOptions, LinkStyleValue>({
+      OptionsClass: LinkStyleOptions,
+      nameKey: `rules.link-style.${optionsKey}.name`,
+      descriptionKey: `rules.link-style.${optionsKey}.description`,
+      optionsKey,
+      records: [
+        {value: 'no-change', description: 'Leave this type of link unchanged.'},
+        {value: 'markdown', description: 'Use Markdown link syntax.'},
+        {value: 'wiki', description: 'Use Obsidian wiki link syntax.'},
+      ],
+    }));
+  }
+}
+
+function wikiToMarkdown(text: string, image: boolean): string {
+  const expression = image ? /!\\[\\[([^\\]\
|]+)(?:\\|([^\\]\
|]+))?\\]\\]/g : /(?<!!)\\[\\[([^\\]\
|]+)(?:\\|([^\\]\
|]+))?\\]\\]/g;
+  return text.replace(expression, (_match, target: string, display: string | undefined) => {
+    if (image) {
+      const alt = display && !/^\\d+(?:x\\d+)?$/.test(display) ? display : target;
+      return `![${alt}](${target})`;
+    }
+
+    return `[${display ?? defaultHeadingDisplay(target)}](${target})`;
+  });
+}
+
+function markdownToWiki(text: string, image: boolean): string {
+  let result = '';
+  let position = 0;
+
+  while (position < text.length) {
+    const startsImage = text.startsWith('![', position);
+    const startsLink = text[position] === '[' && !startsImage;
+    if ((!image && !startsLink) || (image && !startsImage)) {
+      result += text[position++];
+      continue;
+    }
+
+    const parsed = parseMarkdownLink(text, position + (image ? 1 : 0));
+    if (!parsed || parsed.target.includes('://')) {
+      result += text[position++];
+      continue;
+    }
+
+    const display = unescapeMarkdown(parsed.label);
+    const target = unescapeMarkdown(parsed.target);
+    if (image) {
+      result += `![[${target}${display === '' || display === target ? '' : `|${display}`}]]`;
+    } else {
+      result += `[[${target}${display === target || display === defaultHeadingDisplay(target) ? '' : `|${display}`}]]`;
+    }
+    position = parsed.end;
+  }
+
+  return result;
+}
+
+function parseMarkdownLink(text: string, start: number): MarkdownLink | null {
+  let position = start + 1;
+  let nesting = 1;
+  for (; position < text.length; position++) {
+    if (text[position] === '\
' || text[position] === '\\r') return null;
+    if (text[position] === '\\\') {
+      position++;
+    } else if (text[position] === '[') {
+      nesting++;
+    } else if (text[position] === ']' && --nesting === 0) {
+      break;
+    }
+  }
+  if (nesting !== 0 || text[position + 1] !== '(') return null;
+
+  const label = text.slice(start + 1, position);
+  const destinationStart = position + 2;
+  if (text[destinationStart] === '\
' || text[destinationStart] === '\\r') return null;
+
+  if (/\\s/.test(text[destinationStart] ?? '')) {
+    let angledStart = destinationStart;
+    while (text[angledStart] === ' ' || text[angledStart] === '\	') angledStart++;
+    if (text[angledStart] !== '<') return null;
+    const angledEnd = findUnescaped(text, '>', angledStart + 1);
+    if (angledEnd === -1 || /\\r|\
/.test(text.slice(angledStart, angledEnd + 1))) return null;
+    let end = angledEnd + 1;
+    while (text[end] === ' ' || text[end] === '\	') end++;
+    return text[end] === ')' ? {end: end + 1, label, target: text.slice(angledStart + 1, angledEnd)} : null;
+  }
+
+  if (text[destinationStart] === '<') {
+    const destinationEnd = findUnescaped(text, '>', destinationStart + 1);
+    if (destinationEnd === -1 || /\\r|\
/.test(text.slice(destinationStart, destinationEnd + 1)) || text[destinationEnd + 1] !== ')') return null;
+    return {end: destinationEnd + 2, label, target: text.slice(destinationStart + 1, destinationEnd)};
+  }
+
+  let nestingParens = 0;
+  for (let end = destinationStart; end < text.length; end++) {
+    const character = text[end];
+    if (character === '\
' || character === '\\r' || /\\s/.test(character)) return null;
+    if (character === '\\\') {
+      end++;
+    } else if (character === '(') {
+      nestingParens++;
+    } else if (character === ')') {
+      if (nestingParens === 0) return {end: end + 1, label, target: text.slice(destinationStart, end)};
+      nestingParens--;
+    }
+  }
+  return null;
+}
+
+function findUnescaped(text: string, character: string, start: number): number {
+  for (let position = start; position < text.length; position++) {
+    if (text[position] === '\\\') position++;
+    else if (text[position] === character) return position;
+  }
+  return -1;
+}
+
+function unescapeMarkdown(value: string): string {
+  return value.replace(/\\\\(.)/g, '$1');
+}
+
+function defaultHeadingDisplay(target: string): string {
+  const headingIndex = target.indexOf('#');
+  if (headingIndex === -1) return target;
+  const page = target.slice(0, headingIndex);
+  const heading = target.slice(headingIndex + 1);
+  return page === '' ? heading : `${page} > ${heading}`;
+}
